const today = new Date().toISOString().split('T')[0];
const weekAgo = new Date(Date.now() - 7*86400000).toISOString().split('T')[0];

let mtl = '';
try { const b = $('S3: Read MTL').first().binary?.data; if(b) mtl = Buffer.from(b.data,'base64').toString('utf-8'); } catch(e) {}

// Count tasks by area and status
const areas = ['faith','family','business','consulting','work','health','home','personal'];
const stats = {};
for (const a of areas) stats[a] = { total: 0, completed: 0, overdue: 0, dueThisWeek: 0 };

const nextWeek = new Date(Date.now() + 7*86400000).toISOString().split('T')[0];

// Open tasks
const openRe = /- \[ \] .+?\[area:: (\w+)\].*?(?:\[due:: (\d{4}-\d{2}-\d{2})\])?/g;
let m;
while ((m = openRe.exec(mtl)) !== null) {
  const area = m[1]; const due = m[2];
  if (stats[area]) {
    stats[area].total++;
    if (due && due < today) stats[area].overdue++;
    if (due && due >= today && due <= nextWeek) stats[area].dueThisWeek++;
  }
}

// Completed tasks (- [x])
const doneRe = /- \[x\] .+?\[area:: (\w+)\]/g;
while ((m = doneRe.exec(mtl)) !== null) {
  if (stats[m[1]]) stats[m[1]].completed++;
}

// Q2 Rocks
const rocks = [
  { area: 'faith', rock: 'Launch social media Bible study (4 sessions)' },
  { area: 'family', rock: 'Marriage Alignment Questionnaire + bi-weekly check-in' },
  { area: 'business', rock: 'Ship MVP — website, offer, 3 outreach (Echelon Seven)' },
  { area: 'work', rock: 'Deliver Union project + position for exit' },
  { area: 'health', rock: 'Hip decision + 3x/week gym for 8 weeks' }
];

// Build HTML digest
let html = `<h1>Weekly Needle Mover Digest</h1><p>Week ending ${today}</p>`;
html += '<h2>Q2 Rock Progress</h2><table border="1" cellpadding="5"><tr><th>Rock</th><th>Open</th><th>Done</th><th>Overdue</th></tr>';
for (const r of rocks) {
  const s = stats[r.area] || { total:0, completed:0, overdue:0 };
  html += `<tr><td><strong>${r.area}</strong>: ${r.rock}</td><td>${s.total}</td><td>${s.completed}</td><td>${s.overdue > 0 ? '<span style="color:red">' + s.overdue + '</span>' : '0'}</td></tr>`;
}
html += '</table>';

html += '<h2>All Areas</h2><table border="1" cellpadding="5"><tr><th>Area</th><th>Open</th><th>Done</th><th>Due This Week</th><th>Overdue</th></tr>';
for (const [area, s] of Object.entries(stats)) {
  if (s.total + s.completed === 0) continue;
  html += `<tr><td>${area}</td><td>${s.total}</td><td>${s.completed}</td><td>${s.dueThisWeek}</td><td>${s.overdue}</td></tr>`;
}
html += '</table>';

const log = JSON.stringify({ workflow: 'weekly-digest', run_date: today, finished_at: new Date().toISOString(), status: 'success' }, null, 2);

return [{ json: { html, today, logKey: `99_System/logs/weekly-digest-${today}.json`, logContent: log } }];

